effect.script:
function animate(env,el,p) {
    if( env.editMode=="eyedropper-drag" && env.selected ) {
        el.shaderGroups = [1];
    } else {
        el.shaderGroups = [0];
    }
    return el;
}

effect.shader:
void main() {

    highp mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );

    highp mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );

    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec3 spotColorYUV = color.rgb * rgb2yuv;
    vec3 texColorYUV = texColor.rgb * rgb2yuv;
    spotColorYUV.yz *= choke;
    texColorYUV.yz *= choke;
    float b = max(threshold-feather,0.);
    float a = min(threshold+feather,1.);
    float p = smoothstep( a, min(b,a-0.01), length(spotColorYUV - texColorYUV));

    vec3 desatYUV = texColorYUV;
    desatYUV.yz = desatYUV.yz * saturation / 2.0;
    vec4 desaturatedColor = vec4(desatYUV * yuv2rgb, texColor.a);

    gl_FragColor = mix(desaturatedColor,texColor,p);
}
